func solve(prices []int64, strategy []int64, k int64) int64 {
    n := len(prices)
    maxProfit := 0

    // Calculate the original profit
    originalProfit := 0
    for i := 0; i < n; i++ {
        originalProfit += int64(strategy[i]) * prices[i]
    }
    maxProfit = originalProfit

    // Try all possible k-length subarrays to modify
    for i := 0; i <= n-k; i++ {
        // Create a modified strategy
        modifiedStrategy := make([]int64, n)
        copy(modifiedStrategy, strategy)
        // Set the first k/2 elements to 0 (hold)
        for j := i; j < i+(k/2); j++ {
            modifiedStrategy[j] = 0
        }
        // Set the last k/2 elements to 1 (sell)
        for j := i + (k/2); j < i+k; j++ {
            modifiedStrategy[j] = 1
        }

        // Calculate the profit with the modified strategy
        currentProfit := 0
        for j := 0; j < n; j++ {
            currentProfit += int64(modifiedStrategy[j]) * prices[j]
        }

        // Update maxProfit if current is larger
        if currentProfit > maxProfit {
            maxProfit = currentProfit
        }
    }

    return int64(maxProfit)
}
